enum TransactionType {
    DEPOSIT,
    WITHDRAW
}

final class TransactionProcessor {

    private TransactionProcessor() {
    }

    static TransactionResult deposit(@NonNull Account account, @NonNull BigDecimal amount) {
        if (!isValidAmount(amount)) {
            return new TransactionResult(false, "Amount must be greater than zero");
        }
        synchronized (account) {
            account.setBalance(account.getBalance().add(amount).setScale(2, RoundingMode.HALF_UP));
            return new TransactionResult(true, "Deposit completed");
        }
    }

    static TransactionResult withdraw(@NonNull Account account, @NonNull BigDecimal amount) {
        if (!isValidAmount(amount)) {
            return new TransactionResult(false, "Amount must be greater than zero");
        }
        synchronized (account) {
            if (account.getBalance().compareTo(amount) < 0) {
                return new TransactionResult(false, "Insufficient funds");
            }
            account.setBalance(account.getBalance().subtract(amount).setScale(2, RoundingMode.HALF_UP));
            return new TransactionResult(true, "Withdrawal completed");
        }
    }

    private static boolean isValidAmount(BigDecimal amount) {
        return amount != null && amount.compareTo(BigDecimal.ZERO) > 0;
    }
}

final class TransactionResult {
    private final boolean successful;
    private final String message;

    TransactionResult(boolean successful, @NonNull String message) {
        this.successful = successful;
        this.message = message;
    }

    boolean isSuccessful() {
        return successful;
    }

    String getMessage() {
        return message;
    }
}

